import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';

// Mock analytics-buffer so audit logs don't hit the filesystem.
const { mockBufferWrite } = vi.hoisted(() => ({
  mockBufferWrite: vi.fn(),
}));

vi.mock('../../lib/analytics-buffer.js', () => ({
  bufferWrite: mockBufferWrite,
  flush: vi.fn(),
  pendingCount: vi.fn(() => 0),
  _resetForTesting: vi.fn(),
}));

import { secretHandler } from '../../posttool/secret-handler.js';
import type { HookInput } from '../../types.js';
import { createTestContext } from '../fixtures/test-context.js';
import { NEGATIVE_CORPUS } from '../fixtures/negative-corpus.js';
import { POSITIVE_SEEDS } from '../fixtures/positive-seeds.js';

function makeInput(overrides: Partial<HookInput> = {}): HookInput {
  return {
    tool_name: 'Read',
    session_id: 'sess-test',
    tool_input: { file_path: '/tmp/x.txt' },
    tool_output: '',
    ...overrides,
  };
}

let testCtx: ReturnType<typeof createTestContext>;
const ORIGINAL_ENV = process.env.ORK_SECRET_HOOK;

beforeEach(() => {
  testCtx = createTestContext();
  mockBufferWrite.mockReset();
  delete process.env.ORK_SECRET_HOOK;
});

afterEach(() => {
  if (ORIGINAL_ENV === undefined) delete process.env.ORK_SECRET_HOOK;
  else process.env.ORK_SECRET_HOOK = ORIGINAL_ENV;
});

// ---------------------------------------------------------------------------
// 1. Negative corpus — must NOT match any pattern (anti-FP)
// ---------------------------------------------------------------------------
describe('secretHandler — negative corpus (anti-FP)', () => {
  for (const { name, text } of NEGATIVE_CORPUS) {
    it(`does not flag ${name} in REDACT mode`, () => {
      // Arrange
      process.env.ORK_SECRET_HOOK = 'REDACT';
      const input = makeInput({ tool_output: text });

      // Act
      const result = secretHandler(input, testCtx);

      // Assert — silent success means no detection (no hookSpecificOutput)
      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
      expect(result.hookSpecificOutput).toBeUndefined();
    });
  }
});

// ---------------------------------------------------------------------------
// 2. Positive seeds — bounded patterns redact, critical patterns gate
// ---------------------------------------------------------------------------
describe('secretHandler — positive seeds (bounded patterns redact)', () => {
  const BOUNDED = ['github-pat', 'anthropic-key', 'openai-key', 'aws-access-key-id', 'slack-token'];

  for (const patternName of BOUNDED) {
    const seeds = POSITIVE_SEEDS[patternName] ?? [];
    seeds.forEach((seed, idx) => {
      it(`redacts ${patternName} seed #${idx + 1}`, () => {
        // Arrange
        process.env.ORK_SECRET_HOOK = 'REDACT';
        const input = makeInput({ tool_output: seed });

        // Act
        const result = secretHandler(input, testCtx);

        // Assert
        expect(result.hookSpecificOutput).toBeDefined();
        const updated = result.hookSpecificOutput?.updatedToolOutput as string;
        expect(updated).toContain(`[REDACTED:${patternName}]`);
        // Critical pattern marker should not appear (this is bounded redact path)
        expect(updated).not.toContain('[BLOCKED by ork:secret-handler');
      });
    });
  }
});

describe('secretHandler — positive seeds (critical patterns gate)', () => {
  const CRITICAL = ['ssh-private-key', 'gpg-private-key', 'aws-secret-access-key'];

  for (const patternName of CRITICAL) {
    const seeds = POSITIVE_SEEDS[patternName] ?? [];
    seeds.forEach((seed, idx) => {
      it(`gates entire output for ${patternName} seed #${idx + 1}`, () => {
        // Arrange
        process.env.ORK_SECRET_HOOK = 'REDACT';
        const input = makeInput({ tool_output: seed });

        // Act
        const result = secretHandler(input, testCtx);

        // Assert
        const updated = result.hookSpecificOutput?.updatedToolOutput as string;
        expect(updated).toContain('[BLOCKED by ork:secret-handler');
        expect(updated).toContain(patternName);
        // Original secret content must not appear in gated message
        expect(updated).not.toContain(seed);
      });
    });
  }
});

// ---------------------------------------------------------------------------
// 3. Mode behavior
// ---------------------------------------------------------------------------
describe('secretHandler — mode behavior', () => {
  const SECRET = 'ghp_aBcDeFgHiJkLmNoPqRsTuVwXyZ0123456789AB';

  it('OFF returns silentSuccess and does not log audit', () => {
    // Arrange
    process.env.ORK_SECRET_HOOK = 'OFF';
    const input = makeInput({ tool_output: SECRET });

    // Act
    const result = secretHandler(input, testCtx);

    // Assert
    expect(result.continue).toBe(true);
    expect(result.suppressOutput).toBe(true);
    expect(result.hookSpecificOutput).toBeUndefined();
    expect(mockBufferWrite).not.toHaveBeenCalled();
  });

  it('AUDIT writes sidecar log and does NOT mutate output', () => {
    // Arrange
    process.env.ORK_SECRET_HOOK = 'AUDIT';
    const input = makeInput({ tool_output: SECRET });

    // Act
    const result = secretHandler(input, testCtx);

    // Assert — audit logs but no hookSpecificOutput mutation
    expect(result.hookSpecificOutput).toBeUndefined();
    expect(mockBufferWrite).toHaveBeenCalled();
    const [, payload] = mockBufferWrite.mock.calls[0];
    expect(payload).toContain('"action":"audit"');
    expect(payload).toContain('"pattern_name":"github-pat"');
  });

  it('REDACT for bounded pattern returns updatedToolOutput with [REDACTED:type]', () => {
    // Arrange
    process.env.ORK_SECRET_HOOK = 'REDACT';
    const input = makeInput({ tool_output: `prefix ${SECRET} suffix` });

    // Act
    const result = secretHandler(input, testCtx);

    // Assert
    expect(result.hookSpecificOutput?.hookEventName).toBe('PostToolUse');
    expect(result.hookSpecificOutput?.updatedToolOutput).toBe('prefix [REDACTED:github-pat] suffix');
  });

  it('REDACT for critical pattern returns gate message', () => {
    // Arrange
    process.env.ORK_SECRET_HOOK = 'REDACT';
    const input = makeInput({
      tool_output: '-----BEGIN OPENSSH PRIVATE KEY-----\nblob\n-----END OPENSSH PRIVATE KEY-----',
    });

    // Act
    const result = secretHandler(input, testCtx);

    // Assert
    const updated = result.hookSpecificOutput?.updatedToolOutput as string;
    expect(updated).toContain('[BLOCKED by ork:secret-handler');
    expect(updated).toContain('ssh-private-key');
  });

  it('unknown env value defaults to OFF', () => {
    // Arrange
    process.env.ORK_SECRET_HOOK = 'WHATEVER';
    const input = makeInput({ tool_output: SECRET });

    // Act
    const result = secretHandler(input, testCtx);

    // Assert
    expect(result.hookSpecificOutput).toBeUndefined();
    expect(mockBufferWrite).not.toHaveBeenCalled();
  });
});

// ---------------------------------------------------------------------------
// 4. Tool guard — only PROCESSED_TOOLS are scanned
// ---------------------------------------------------------------------------
describe('secretHandler — tool guard', () => {
  const SECRET = 'ghp_aBcDeFgHiJkLmNoPqRsTuVwXyZ0123456789AB';

  it.each(['Write', 'Edit', 'mcp__memory__search_nodes', 'Task', 'WebFetch'])(
    'skips %s (not in PROCESSED_TOOLS)',
    (toolName) => {
      // Arrange
      process.env.ORK_SECRET_HOOK = 'REDACT';
      const input = makeInput({ tool_name: toolName, tool_output: SECRET });

      // Act
      const result = secretHandler(input, testCtx);

      // Assert
      expect(result.hookSpecificOutput).toBeUndefined();
      expect(mockBufferWrite).not.toHaveBeenCalled();
    },
  );

  it.each(['Read', 'Bash', 'Grep', 'Glob'])('processes %s', (toolName) => {
    // Arrange
    process.env.ORK_SECRET_HOOK = 'REDACT';
    const input = makeInput({ tool_name: toolName, tool_output: SECRET });

    // Act
    const result = secretHandler(input, testCtx);

    // Assert
    expect(result.hookSpecificOutput).toBeDefined();
    expect(result.hookSpecificOutput?.updatedToolOutput).toContain('[REDACTED:github-pat]');
  });
});

// ---------------------------------------------------------------------------
// 5. Perf benchmark — catch catastrophic backtracking
// ---------------------------------------------------------------------------
describe('secretHandler — performance', () => {
  it('processes 50KB output in under 50ms', () => {
    // Arrange
    process.env.ORK_SECRET_HOOK = 'REDACT';
    // Filler must end on a non-word char so \b matches before the secret.
    const filler = `${'A'.repeat(24999)} `;
    const tail = ` ${'B'.repeat(24998)}`;
    const secret = 'ghp_aBcDeFgHiJkLmNoPqRsTuVwXyZ0123456789AB';
    const big = `${filler}${secret}${tail}`;
    const input = makeInput({ tool_output: big });

    // Act
    const start = performance.now();
    const result = secretHandler(input, testCtx);
    const elapsedMs = performance.now() - start;

    // Assert — correctness AND perf
    expect(result.hookSpecificOutput?.updatedToolOutput).toContain('[REDACTED:github-pat]');
    expect(elapsedMs).toBeLessThan(50);
  });
});
